var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"여기 있었군, 베로니카 양. 오래 찾았네.","JPN":"ここにいたか、ベロニカ。探したぞ。","ENG":"There you are, Veronica. I've been looking everywhere for you.","TWN":"妳在這裡啊，貝洛妮卡，我一直在找妳。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님......?","JPN":"ご主人様……？","ENG":"Master?","TWN":"主人……？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"죄송합니다. 먼저 인사드렸어야 했는데 오신 줄도 모르고 있었군요.","JPN":"申し訳ございません。いらしたことに気付きませんでした。","ENG":"Apologies. I should have greeted you first. I had no idea you were here.","TWN":"對不起，我應該先向您打聲招呼的，沒想到您先來了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"침식재난 때 자네 고생이 많지 않았나.","JPN":"侵食災害の時はだいぶ苦労をかけてしまってすまない。","ENG":"You've been through a lot during the Corruption Disaster.","TWN":"侵蝕災難的時候，真是辛苦妳了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"소미 양에게 들은 이야기도 신경 쓰는 눈치고.","JPN":"ヒマワリさんから聞いた話も気にしているようだし。","ENG":"And the rumor Ms. Shim told you about seemed to have gotten you all riled up.","TWN":"小美說的話，妳很在意吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......표정을 제대로 간수하지 못했군요. 주의하겠습니다.","JPN":"……表情管理がしっかりできていなかったようですね。気を付けます。","ENG":"I shouldn't have let my emotions show. Please forgive me. It won't happen again.","TWN":"……看來是我表現得太明顯了，我以後會注意的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"질책하려는 건 아닐세. 그냥 자네가 장기 계약을 거절한 사정과 관계가 있는지 해서 말이야.","JPN":"別に責めているわけではない。ただ、君が長期契約を断る理由と関係している気がしてな。","ENG":"I'm not here to scold you. I'm just curious if this has anything to do with why you turned down my long-term offer.","TWN":"我不是責怪妳，我只是在想，妳拒絕和我們續簽，是不是跟這個有關係。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"계약도 며칠 뒤면 끝나지만, 아무래도 마음에 걸려서 말일세.","JPN":"契約はあと数日で終わるんだが、やはり気になってね。","ENG":"I know our contract is over in a few days, but I'm getting worried about you.","TWN":"合約過幾天就到期了，我很擔心啊。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는, 기억이 없습니다.","JPN":"私は、記憶を失いました。","ENG":"I... don't remember anything.","TWN":"我其實什麼都不記得了。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"응? 기억 상실이란 말인가?","JPN":"ふむ？　記憶喪失ということか？","ENG":"Huh? You mean you've got amnesia?","TWN":"嗯？妳的意思是妳失憶了？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 모네도 그렇게 말하더군요.","JPN":"はい。モネもそう言っていました。","ENG":"Yes. That's how Mone put it, too.","TWN":"嗯，莫妮也是那麼說的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"깨어났을 때 기억하는 거라고는 제가 메이드였다는 사실과......","JPN":"目が覚めた時に覚えていたのは自分がメイドだったということと……","ENG":"The only thing I remembered when I woke up was that I used to be a maid...","TWN":"我醒來的時候，就只記得我是個女僕……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"소중한 무언가를 지키려고 했다는 것뿐이었어요.","JPN":"大切な何かを守ろうとしていたということだけでした。","ENG":"And that I was trying to protect something precious.","TWN":"並且要守護什麼珍貴的東西。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그래서 메이드 일을 하다 보면 기억이 되돌아올 수도 있다는 생각에, 지금처럼 지내고 있었습니다.","JPN":"それで、メイドの仕事をしていれば記憶が戻ってくるかもしれないと思って、今のように過ごしております。","ENG":"I figured my memories might return if I continued to serve as a maid. Hence my current situation.","TWN":"我在想，如果我一直做女僕，是不是哪一天就可以想起來，所以才會這麼過下去。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"흐음. 하지만 한 곳에 오래 머물지 않는 이유가 있나?","JPN":"ふむ。しかし1ヶ所に長く滞在しないのはどんな理由で？","ENG":"Hmm... But is there a reason why you won't stay in one place for long?","TWN":"唔，那妳為什麼不在一個地方停留呢？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"매번 이리저리 옮겨 다니는 것도 고생일 텐데.","JPN":"毎回拠点を変えるのは大変だと思うんだが。","ENG":"It must be a hassle having to move around so much.","TWN":"每次都要換個地方，豈不是很麻煩。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이 일을 하면서 이따금 과거의 순간이 떠오를 때도 있었습니다.","JPN":"この仕事をしていると時々、昔の記憶が一瞬だけ蘇る時があります。","ENG":"There have been moments when bits of my past flashed across my mind.","TWN":"這個工作，偶爾會讓我想起過去的某個瞬間。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"처음에는 막연하게만 느껴졌지만...... 모네를 침식체로부터 구했을 때 확실해졌어요.","JPN":"最初は漠然としたイメージに過ぎませんでしたが……侵食体からモネを助けた時、確かに見たのです。","ENG":"At first I thought it was random... but it became clear when I saved Mone from the Corrupted Object.","TWN":"一開始只是覺得很茫然……後來從侵蝕體手裡救出莫妮的時候記憶便清晰了許多。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"장소와 시간만 다를 뿐이지, 떠오르는 광경은 늘 피웅덩이에 비친 제 모습뿐이었습니다.","JPN":"時と場所が違うだけで、脳裏に浮かぶ光景はいつも血溜まりに映る自分の姿でした。","ENG":"All the memories were of different times and places, but they all had my reflection on a puddle of blood.","TWN":"除了時間和地點不同，浮現的場景都是映在血坑裡的我。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 이후부터는...... 과거의 저란 사람이 두려워졌습니다.","JPN":"それから……私は過去の自分という人間が怖くなりました。","ENG":"Ever since then... I've been afraid of finding out whom I used to be.","TWN":"之後……我突然就覺得過去的我很可怕。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"과거를 찾겠다고 피 묻은 손으로 주인님을 모시던, 지금의 저도 말이죠.","JPN":"過去を取り戻すために血まみれの手でご主人様に仕える、今の自分もです。","ENG":"Just as I fear my current self, serving you with these bloodied hands just so I can reclaim my past.","TWN":"為了找回過去，用沾滿鮮血的手侍奉主人的我也很可怕。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......그렇군.","JPN":"……そうか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"실은 자네 기운 차리라고 선물을 하나 준비해 왔다네.","JPN":"実は君には元気になってもらいたくて、プレゼントを一つ持ってきた。","ENG":"Well, I brought you a present to cheer you up.","TWN":"其實我給妳準備了一件禮物，希望妳能打起精神。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"선물? 어떤 선물 말씀이시죠?","JPN":"プレゼントですか？　どんなモノでしょうか？","ENG":"Present? What present?","TWN":"禮物？什麼禮物？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"바로 이 황금 머신 갑이 그려진 일일 휴가 티켓일세.","JPN":"黄金マシーン-甲-が描かれたこの一日休暇チケットさ。","ENG":"It's a leave coupon with the image of the Golden Machine G.A.P.","TWN":"是一張畫上了黃金甲·機器人的一日休假券。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"연차, 병가 상관없이 원할 때 언제든 쓸 수 있는 만능 휴가 티켓이지.","JPN":"有給休暇や病欠などは関係なく、好きな時にいつでも使える万能休暇チケットだ。","ENG":"You can use this anytime to take some time off, regardless of the reason.","TWN":"不管是年假還是病假，任何時候都可以用，是一張萬能休假券。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러니 자네 편한 대로 사용하게.","JPN":"だから好きに使うといい。","ENG":"So use it as you please.","TWN":"所以妳想什麼時候用就什麼時候用吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"소문의 메이드를 찾아 보거나, 모네 양과 같이 놀러 가거나, 시윤 군에게 팔거나.","JPN":"噂のメイドを探すのもよし、モネと一緒に遊びにいくのもよし。あと、アキヤマ君に売るのもアリだな。","ENG":"You can go find those maids they're talking about online, or get some fresh air with Mone. You could even sell it to Shiyoon.","TWN":"休假的時候可以去找傳聞中的女僕，或者和莫妮出去玩，又或者賣給時雲。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼 가 보겠네. 너무 무리하진 말게.","JPN":"ではそろそろ帰るぞ。あまり無理しないように。","ENG":"I'll get going then. Take it easy.","TWN":"那我走了，不要太勉強自己。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"......감사합니다, 상냥하신 주인님.","JPN":"……ありがとうございます。心優しいご主人様。","ENG":"Thank you, kind Master.","TWN":"……謝謝你，我親切的主人。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};